260:         long baseOffset,
261:         long logAppendTime,
262:         RuntimeException topLevelException,
263:         Function<Integer, RuntimeException> recordExceptions
264:     ) {
265:         final FinalState tryFinalState = (topLevelException == null) ? FinalState.SUCCEEDED : FinalState.FAILED;
266:         if (tryFinalState == FinalState.SUCCEEDED) {
267:             log.trace("Successfully produced messages to {} with base offset {}.", topicPartition, baseOffset);
268:         } else {
269:             log.trace("Failed to produce messages to {} with base offset {}.", topicPartition, baseOffset, topLevelException);
270:         }
271: 
272:         if (this.finalState.compareAndSet(null, tryFinalState)) {
273:             completeFutureAndFireCallbacks(baseOffset, logAppendTime, recordExceptions);
274:             return true;
275:         }
276: 
277:         if (this.finalState.get() != FinalState.SUCCEEDED) {
278:             if (tryFinalState == FinalState.SUCCEEDED) {
279:                 // Log if a previously unsuccessful batch succeeded later on.
280:                 log.debug("ProduceResponse returned {} for {} after batch with base offset {} had already been {}.",
281:                     tryFinalState, topicPartition, baseOffset, this.finalState.get());
282:             } else {
283:                 // FAILED --> FAILED and ABORTED --> FAILED transitions are ignored.
284:                 log.debug("Ignored state transition {} -> {} for {} batch with base offset {}",
285:                     this.finalState.get(), tryFinalState, topicPartition, baseOffset);
286:             }
287:         } else {
288:             // A SUCCESSFUL batch must not attempt another state change.
289:             throw new IllegalStateException("A " + this.finalState.get() + " batch must not attempt another state change to " + tryFinalState);
290:         }
291:         return false;
