294:     private void completeFutureAndFireCallbacks(
295:         long baseOffset,
296:         long logAppendTime,
297:         Function<Integer, RuntimeException> recordExceptions
298:     ) {
299:         // Set the future before invoking the callbacks as we rely on its state for the `onCompletion` call
300:         produceFuture.set(baseOffset, logAppendTime, recordExceptions);
301: 
302:         // execute callbacks
303:         for (int i = 0; i < thunks.size(); i++) {
304:             try {
305:                 Thunk thunk = thunks.get(i);
306:                 if (thunk.callback != null) {
307:                     if (recordExceptions == null) {
308:                         RecordMetadata metadata = thunk.future.value();
309:                         thunk.callback.onCompletion(metadata, null);
310:                     } else {
311:                         RuntimeException exception = recordExceptions.apply(i);
312:                         thunk.callback.onCompletion(null, exception);
313:                     }
314:                 }
315:             } catch (Exception e) {
316:                 log.error("Error executing user-provided callback on message for topic-partition '{}'", topicPartition, e);
317:             }
318:         }
319: 
320:         produceFuture.done();
321:     }
