599:                             Errors.forCode(p.errorCode()),
600:                             p.baseOffset(),
601:                             p.logAppendTimeMs(),
602:                             p.logStartOffset(),
603:                             p.recordErrors()
604:                                 .stream()
605:                                 .map(e -> new ProduceResponse.RecordError(e.batchIndex(), e.batchIndexErrorMessage()))
606:                                 .collect(Collectors.toList()),
607:                             p.errorMessage(),
608:                             p.currentLeader());
